    <script>
        let rawData = [];
        let filteredData = [];
        let charts = {};
        const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

        async function init() {
            try {
                const response = await fetch('data.json');
                rawData = await response.json();
                populateFilters();
                applyFilters();
                ['filterMonth', 'filterAgent', 'filterActionBy'].forEach(id => {
                    document.getElementById(id).addEventListener('change', applyFilters);
                });
                document.getElementById('tableSearch').addEventListener('input', applyFilters);
            } catch (err) {
                console.error("Dashboard Init Failed:", err);
            }
        }

        function populateFilters() {
            const months = new Set();
            const teams = new Set();
            const names = new Set();

            rawData.forEach(t => {
                if (t['Resolved Date']) {
                    const d = new Date(t['Resolved Date']);
                    months.add(`${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}`);
                }
                if (t['Agent Name']) teams.add(t['Agent Name']);
                if (t['Action by']) names.add(t['Action by']);
            });

            const fill = (id, items, label) => {
                const el = document.getElementById(id);
                el.innerHTML = `<option value="all">All ${label}</option>`;
                Array.from(items).sort().forEach(i => {
                    const opt = document.createElement('option');
                    opt.value = i;
                    opt.textContent = id === 'filterMonth' ? `${monthNames[i.split('-')[1]-1]} ${i.split('-')[0]}` : i;
                    el.appendChild(opt);
                });
            };

            fill('filterMonth', months, 'Months');
            fill('filterAgent', teams, 'Support Teams');
            fill('filterActionBy', names, 'Personnel');
        }

        function applyFilters() {
            const m = document.getElementById('filterMonth').value;
            const ag = document.getElementById('filterAgent').value;
            const ab = document.getElementById('filterActionBy').value;
            const search = document.getElementById('tableSearch').value.toLowerCase();

            filteredData = rawData.filter(t => {
                if (m !== 'all') {
                    const d = new Date(t['Resolved Date']);
                    if (`${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}` !== m) return false;
                }
                if (ag !== 'all' && t['Agent Name'] !== ag) return false;
                if (ab !== 'all' && t['Action by'] !== ab) return false;

                if (search) {
                    const text = `${t.ID} ${t.Subject} ${t['Resolution Notes']}`.toLowerCase();
                    if (!text.includes(search)) return false;
                }
                return true;
            });

            updateUI();
        }

        function updateUI() {
            updateKPIs();
            renderTrendChart();
            renderMethodChart();
            renderPerformanceChart();
            renderRootCauses();
            renderTable();
        }

        function updateKPIs() {
            document.getElementById('kpiTotalTickets').textContent = filteredData.length.toLocaleString();

            const personnel = new Set(filteredData.map(t => t['Action by']).filter(x => x));
            document.getElementById('kpiActivePersonnel').textContent = personnel.size;

            const bus = new Set(filteredData.map(t => t['BU Name']).filter(x => x));
            document.getElementById('kpiBUCount').textContent = bus.size;

            const categories = {};
            filteredData.forEach(t => {
                if (t.Category) categories[t.Category] = (categories[t.Category] || 0) + 1;
            });
            const topCat = Object.entries(categories).sort((a,b) => b[1]-a[1])[0];
            document.getElementById('kpiTopCategory').textContent = topCat ? topCat[0] : 'N/A';
            document.getElementById('kpiTopCategory').title = topCat ? topCat[0] : 'N/A';
        }

        function renderTrendChart() {
            const map = {};
            filteredData.forEach(t => {
                const d = new Date(t['Resolved Date']);
                const key = `${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}`;
                map[key] = (map[key] || 0) + 1;
            });

            const sortedKeys = Object.keys(map).sort();
            const labels = sortedKeys.map(k => `${monthNames[k.split('-')[1]-1]} ${k.split('-')[0]}`);
            const data = sortedKeys.map(k => map[k]);

            if (charts.trend) charts.trend.destroy();
            const ctx = document.getElementById('trendChart').getContext('2d');
            const gradient = ctx.createLinearGradient(0, 0, 0, 400);
            gradient.addColorStop(0, 'rgba(59, 130, 246, 0.4)');
            gradient.addColorStop(1, 'rgba(59, 130, 246, 0)');

            charts.trend = new Chart(ctx, {
                type: 'line',
                data: {
                    labels: labels,
                    datasets: [{
                        label: 'Tickets',
                        data: data,
                        borderColor: '#3b82f6',
                        backgroundColor: gradient,
                        fill: true,
                        tension: 0.4,
                        borderWidth: 3,
                        pointBackgroundColor: '#3b82f6',
                        pointBorderColor: '#020617',
                        pointHoverRadius: 6
                    }]
                },
                options: {
                    maintainAspectRatio: false,
                    plugins: { legend: { display: false } },
                    scales: {
                        y: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b' } },
                        x: { grid: { display: false }, ticks: { color: '#64748b' } }
                    }
                }
            });
        }

        function renderMethodChart() {
            const map = {};
            filteredData.forEach(t => {
                const m = t['Resolution Method'] || 'N/A';
                map[m] = (map[m] || 0) + 1;
            });

            if (charts.method) charts.method.destroy();
            charts.method = new Chart(document.getElementById('methodChart'), {
                type: 'doughnut',
                data: {
                    labels: Object.keys(map),
                    datasets: [{
                        data: Object.values(map),
                        backgroundColor: ['#3b82f6aa', '#8b5cf6aa', '#10b981aa', '#f59e0baa', '#ef4444aa'],
                        borderColor: '#020617',
                        borderWidth: 4,
                        hoverOffset: 15
                    }]
                },
                options: {
                    maintainAspectRatio: false,
                    cutout: '75%',
                    plugins: {
                        legend: { position: 'bottom', labels: { color: '#94a3b8', boxWidth: 10, padding: 20, font: { size: 10, weight: 'bold' } } }
                    }
                }
            });
        }

        function renderPerformanceChart() {
            const map = {};
            filteredData.forEach(t => {
                const n = t['Action by'] || 'Unknown';
                map[n] = (map[n] || 0) + 1;
            });
            const sorted = Object.entries(map).sort((a,b) => b[1]-a[1]).slice(0, 10);

            if (charts.perf) charts.perf.destroy();
            charts.perf = new Chart(document.getElementById('perfChart'), {
                type: 'bar',
                data: {
                    labels: sorted.map(x => x[0]),
                    datasets: [{
                        data: sorted.map(x => x[1]),
                        backgroundColor: '#10b981aa',
                        borderRadius: 12,
                        hoverBackgroundColor: '#10b981'
                    }]
                },
                options: {
                    indexAxis: 'y',
                    maintainAspectRatio: false,
                    plugins: { legend: { display: false } },
                    scales: {
                        x: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b' } },
                        y: { grid: { display: false }, ticks: { color: '#f8fafc', font: { size: 10, weight: '600' } } }
                    }
                }
            });
        }

        function renderRootCauses() {
            const causeMap = {};
            filteredData.forEach(t => {
                const notes = t['Resolution Notes'] || '';
                const match = notes.match(/Cause\s*::\s*([^,]+)/i);
                if (match && match[1]) {
                    const causeText = match[1].trim().toLowerCase();
                    let normalized = causeText;
                    if (normalized.includes('สัญญา')) normalized = 'Staff Contract Issues / Extensions';
                    if (normalized.includes('notepad') || normalized.includes('ภาษา')) normalized = 'Notepad & Thai Character Encoding';
                    if (normalized.includes('network') || normalized.includes('disconnected')) normalized = 'Network Connection Stability';
                    if (normalized.includes('password') || normalized.includes('login')) normalized = 'Identity & Access Management (IAM)';
                    if (normalized.includes('ie mode') || normalized.includes('edge')) normalized = 'Browser / Legacy IE Compatibility';
                    if (normalized.includes('excel') || normalized.includes('ไวรัส')) normalized = 'Excel Malware / Macro Corruption';
                    if (normalized.includes('เต็ม')) normalized = 'Storage Capacity / Disk Full';

                    causeMap[normalized] = (causeMap[normalized] || 0) + 1;
                }
            });

            const top = Object.entries(causeMap).sort((a,b) => b[1]-a[1]).slice(0, 6);
            const container = document.getElementById('rootCauseContainer');
            container.innerHTML = '';

            top.forEach(([cause, count], i) => {
                const pct = Math.round((count / filteredData.length) * 100) || 0;
                const div = document.createElement('div');
                div.innerHTML = `
                    <div class="flex justify-between items-end mb-1">
                        <span class="text-xs font-bold text-slate-300 capitalize">${cause}</span>
                        <span class="text-[10px] font-black text-slate-500">${count} Tickets</span>
                    </div>
                    <div class="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                        <div class="bg-red-500/50 h-full rounded-full transition-all duration-1000" style="width: ${Math.max(pct, 5)}%"></div>
                    </div>
                `;
                container.appendChild(div);
            });
        }

        function renderTable() {
            const tbody = document.getElementById('mainTableBody');
            tbody.innerHTML = '';
            filteredData.slice(0, 50).forEach(t => {
                const tr = document.createElement('tr');
                tr.className = 'group transition-all hover:translate-x-1';
                tr.innerHTML = `
                    <td class="p-4 bg-slate-900/40 rounded-l-2xl border-y border-l border-slate-800 group-hover:border-blue-500/30 transition-all">
                        <div class="flex flex-col">
                            <span class="text-[10px] font-black text-blue-500">${t.ID}</span>
                            <span class="text-[9px] text-slate-500 font-mono">${t['Resolved Date']}</span>
                        </div>
                    </td>
                    <td class="p-4 bg-slate-900/40 border-y border-slate-800 group-hover:border-blue-500/30">
                        <span class="badge bg-slate-800 text-slate-300 border border-slate-700">${t['BU Name'] || 'N/A'}</span>
                    </td>
                    <td class="p-4 bg-slate-900/40 border-y border-slate-800 group-hover:border-blue-500/30 font-bold text-slate-200">
                        ${t['Agent Name'] || 'N/A'}
