                    <div class="absolute -top-4 -right-4 w-24 h-24 bg-white/10 rounded-full blur-2xl group-hover:scale-150 transition-transform duration-700"></div>
                    <label class="text-[9px] font-black text-blue-200 uppercase tracking-widest mb-4 block">Executive Resolution Insight</label>
                    <p id="modalNotes" class="text-sm text-white font-bold leading-relaxed whitespace-pre-wrap italic">Resolution notes details...</p>
                </div>
            </div>

            <!-- Modal Footer -->
            <div class="p-8 border-t-2 border-slate-50 flex justify-end">
                <button onclick="closeModal()" class="px-10 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-blue-600 hover:shadow-xl hover:shadow-blue-200 transition-all tracking-widest uppercase">Dismiss Details</button>
            </div>
