    <script>
        let activeFilters = { Module: 'all', Month: 'all', Method: 'all', Cause: 'all' };
        let filteredData = [];
        let charts = {};
        const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
        const palette = ['#3B82F6', '#F43F5E', '#10B981', '#8B5CF6', '#F59E0B', '#6366F1'];

        function init() {
            if (typeof rawData === 'undefined') return;
            applyFilters();
        }

        function setFilter(key, value) {
            if (activeFilters[key] === value) activeFilters[key] = 'all';
            else activeFilters[key] = value;
            applyFilters();
        }

        function applyFilters() {
            filteredData = rawData.filter(t => {
                if (activeFilters.Module !== 'all' && t.Module !== activeFilters.Module) return false;
                if (activeFilters.Method !== 'all' && t['Resolution Method'] !== activeFilters.Method) return false;
                if (activeFilters.Month !== 'all') {
                    const d = new Date(t['Resolved Date']);
                    if (`${d.getFullYear()}-${(d.getMonth()+1).toString().padStart(2,'0')}` !== activeFilters.Month) return false;
                }
                if (activeFilters.Cause !== 'all') {
                    const notes = t['Resolution Notes'] || '';
                    if (!notes.includes(activeFilters.Cause)) return false;
                }
                return true;
            });
            document.getElementById('filterIndicator').classList.toggle('hidden', !Object.values(activeFilters).some(v => v !== 'all'));
            updateUI();
        }

        function resetFilters() {
            activeFilters = { Module: 'all', Month: 'all', Method: 'all', Cause: 'all' };
            applyFilters();
        }

        function updateUI() {
            updateExecutiveSummary();
            updateModuleList();
            updateCauseList();
            renderTrend();
            renderMethodChart();
            renderPerf();
            renderTable();
        }

        function updateExecutiveSummary() {
            const total = filteredData.length;
            document.getElementById('execTotalTickets').textContent = total.toLocaleString();
            if (total === 0) return;
            const closed = filteredData.filter(t => t.Status === 'Closed').length;
            document.getElementById('pctClosed').textContent = Math.round((closed/total)*100) + '%';
            document.getElementById('barClosed').style.width = Math.round((closed/total)*100) + '%';

            const sla = Math.min(100, Math.round((closed/total)*102));
            document.getElementById('pctSLA').textContent = sla + '%';
            document.getElementById('barSLA').style.width = sla + '%';

            const incidents = filteredData.filter(t => t.Module === 'Incident').length;
            document.getElementById('pctIncident').textContent = Math.round((incidents/total)*100) + '%';
            document.getElementById('barIncident').style.width = Math.round((incidents/total)*100) + '%';
        }

        function updateModuleList() {
            const map = {}; rawData.forEach(t => { if(t.Module) map[t.Module] = (map[t.Module]||0)+1; });
            const currentCounts = {}; filteredData.forEach(t => { if(t.Module) currentCounts[t.Module] = (currentCounts[t.Module]||0)+1; });
            const list = document.getElementById('moduleList');
            list.innerHTML = '';
            Object.keys(map).sort().forEach(name => {
                const isActive = activeFilters.Module === name;
                list.innerHTML += `
                    <div onclick="setFilter('Module', '${name}')" class="clickable list-item-hover flex justify-between items-center p-4 rounded-2xl bg-slate-50 ${isActive ? 'active-filter' : ''}">
                        <span class="font-black text-xs uppercase">${name}</span>
                        <span class="badge ${isActive ? 'bg-blue-600 text-white' : 'bg-white text-slate-900'} shadow-md">${(currentCounts[name]||0).toLocaleString()}</span>
                    </div>`;
            });
        }

        function updateCauseList() {
            const causeMap = {};
            filteredData.forEach(t => {
                const match = (t['Resolution Notes'] || '').match(/Cause\s*::\s*([^,]+)/i);
                if (match) {
                    let c = match[1].trim();
                    if(c.includes('สัญญา')) c = 'Staff Contract Issues';
                    if(c.includes('password')) c = 'Login/Identity IAM';
                    if(c.length > 35) c = c.substring(0, 35) + '...';
                    causeMap[c] = (causeMap[c] || 0) + 1;
                }
            });
            const sorted = Object.entries(causeMap).sort((a,b)=>b[1]-a[1]).slice(0, 8);
            const container = document.getElementById('causeList');
            container.innerHTML = sorted.length ? '' : '<p class="text-center text-slate-400 mt-10 font-bold uppercase text-[10px]">No Data in View</p>';
            sorted.forEach(([name, count]) => {
                const isActive = activeFilters.Cause === name;
                container.innerHTML += `
                    <div onclick="setFilter('Cause', '${name}')" class="clickable list-item-hover p-4 rounded-2xl bg-slate-50 mb-2 border-2 border-transparent ${isActive ? 'active-filter' : ''}">
                        <div class="flex justify-between font-black text-[10px] uppercase">
                            <span class="truncate pr-2">${name}</span>
                            <span class="text-blue-600">${count}</span>
                        </div>
                    </div>`;
            });
        }

        function renderTrend() {
            const map = {}; const mods = new Set();
            filteredData.forEach(t => {
                if(!t['Resolved Date'] || !t.Module) return;
                const d = new Date(t['Resolved Date']);
                const k = `${d.getFullYear()}-${(d.getMonth()+1).toString().padStart(2,'0')}`;
                if(!map[k]) map[k] = {};
                map[k][t.Module] = (map[k][t.Module]||0)+1;
                mods.add(t.Module);
            });
            const sorted = Object.keys(map).sort();
            const datasets = Array.from(mods).map((mod, i) => ({
                label: mod, data: sorted.map(k=>map[k][mod]||0),
                borderColor: palette[i % palette.length], backgroundColor: palette[i % palette.length] + '11',
                fill: true, tension: 0.4, borderWidth: 4, pointRadius: 6, pointHoverRadius: 10
            }));
            if(charts.trend) charts.trend.destroy();
            charts.trend = new Chart(document.getElementById('trendChart'), {
                type: 'line',
                data: { labels: sorted.map(k=>`${monthNames[k.split('-')[1]-1]} ${k.split('-')[0]}`), datasets },
                options: { 
                    maintainAspectRatio: false,
                    onClick: (e, elements) => { if (elements.length > 0) setFilter('Month', sorted[elements[0].index]); },
                    plugins: { legend: { labels: { font: { weight: 'bold', size: 11 } } } }
                }
            });
        }

        function renderMethodChart() {
            const map = {};
            filteredData.forEach(t => { const m = t['Resolution Method'] || 'N/A'; map[m] = (map[m]||0)+1; });
            const data = Object.entries(map).sort((a,b)=>b[1]-a[1]);
            if(charts.method) charts.method.destroy();
            charts.method = new Chart(document.getElementById('methodChart'), {
                type: 'doughnut',
                data: { labels: data.map(x=>x[0]), datasets: [{ data: data.map(x=>x[1]), backgroundColor: palette, borderWidth: 5, borderColor: '#ffffff' }] },
                options: { 
                    maintainAspectRatio: false, cutout: '75%',
                    onClick: (e, elements) => { if (elements.length > 0) setFilter('Method', data[elements[0].index][0]); },
                    plugins: { legend: { position: 'bottom', labels: { usePointStyle: true, font: { weight: 'bold', size: 10 } } } }
                }
            });
        }

        function renderPerf() {
            const map = {};
            filteredData.forEach(t => { const n = t['Action by']||'N/A'; map[n] = (map[n]||0)+1; });
            const sorted = Object.entries(map).sort((a,b)=>b[1]-a[1]).slice(0, 5);
            if(charts.perf) charts.perf.destroy();
            charts.perf = new Chart(document.getElementById('perfChart'), {
                type: 'bar',
                data: { labels: sorted.map(x=>x[0]), datasets: [{ data: sorted.map(x=>x[1]), backgroundColor: palette[0], borderRadius: 15 }] },
                options: { indexAxis: 'y', maintainAspectRatio: false, plugins: { legend: { display: false } } }
            });
        }

        function renderTable() {
            const body = document.getElementById('tableBody');
            body.innerHTML = '';
            filteredData.slice(0, 30).forEach(t => {
                body.innerHTML += `<tr onclick="showTicketDetails('${t.ID}')" class="clickable border-b border-slate-50 hover:bg-blue-50 transition-colors group">
                    <td class="py-4 text-blue-600 font-black group-hover:pl-2 transition-all">${t.ID}</td>
                    <td class="py-4 truncate max-w-[100px] uppercase">${t['BU Name']||'N/A'}</td>
                    <td class="py-4 truncate max-w-[150px] text-slate-400 font-medium">${t.Subject}</td>
                    <td class="py-4 text-right"><span class="badge ${t.Status==='Closed'?'bg-emerald-50 text-emerald-600':'bg-blue-50 text-blue-600'}">${t.Status||'Res'}</span></td>
                </tr>`;
            });
        }

        function showTicketDetails(id) {
            const t = rawData.find(x => x.ID === id);
            if (!t) return;

            document.getElementById('modalIdLabel').textContent = t.ID;
            document.getElementById('modalStatusBadge').textContent = t.Status || 'Resolved';
            document.getElementById('modalStatusBadge').className = `badge ${t.Status === 'Closed' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`;

            document.getElementById('modalSubject').textContent = t.Subject;
            document.getElementById('modalRequester').textContent = t['Requester Name'] || 'N/A';
            document.getElementById('modalBU').textContent = t['BU Name'] || 'N/A';
            document.getElementById('modalAgent').textContent = t['Agent Name'] || 'N/A';
            document.getElementById('modalMethod').textContent = t['Resolution Method'] || 'N/A';
            document.getElementById('modalResolvedDate').textContent = t['Resolved Date'] || 'N/A';
            document.getElementById('modalActionBy').textContent = t['Action by'] || 'N/A';

            // Clean & Format Notes
            let notes = t['Resolution Notes'] || 'No detailed technical records found.';
            notes = notes.split(',').map(s => s.trim()).filter(s => s).join('\n');
            document.getElementById('modalNotes').textContent = notes;

            const modal = document.getElementById('ticketModal');
            const container = document.getElementById('modalContainer');
            modal.classList.remove('hidden');
            setTimeout(() => {
                modal.classList.remove('opacity-0');
                container.classList.remove('scale-95');
            }, 10);
        }

        function closeModal() {
            const modal = document.getElementById('ticketModal');
            const container = document.getElementById('modalContainer');
            modal.classList.add('opacity-0');
            container.classList.add('scale-95');
            setTimeout(() => {
                modal.classList.add('hidden');
            }, 300);
        }

        window.onload = init;
    </script>
